152	/**
153	 * Normalize a variable reference by stripping optional curly braces.
154	 * '${foo}' → '$foo', '$foo' → '$foo' (unchanged).
155	 * Called before matching against known variable patterns.
156	 */
157	function normalizeVarRef(value: string): string {
158	  if (value.startsWith('${') && value.endsWith('}')) {
159	    return '$' + value.slice(2, -1);
160	  }
161	  return value;
162	}
163	
164	/**
165	 * Resolve a template engine's givens map using a variables context.
166	 * '$writ' → WritDoc, '$vars.<key>' → spiderConfig.variables[key].
167	 * Keys resolving to undefined are omitted from the output.
168	 * Non-'$' prefixed values are passed through as literals.
169	 */
170	function resolveGivens(
171	  givens: Record<string, unknown> | undefined,
172	  context: { writ: WritDoc; spiderConfig: SpiderConfig },
173	): Record<string, unknown> {
174	  const result: Record<string, unknown> = {};
175	  for (const [key, value] of Object.entries(givens ?? {})) {
176	    if (typeof value !== 'string' || !value.startsWith('$')) {
177	      result[key] = value;
178	    } else {
179	      const normalized = normalizeVarRef(value);
180	      if (normalized === '$writ') {
181	        result[key] = context.writ;
182	      } else if (/^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)) {
183	        const varKey = normalized.slice('$vars.'.length);
184	        const resolved = (context.spiderConfig.variables ?? {})[varKey];
185	        if (resolved !== undefined) {
186	          result[key] = resolved;
187	        }
188	        // undefined → omit key entirely
189	      }
190	      // Unrecognized $-prefixed strings are caught at validation time
191	    }
192	  }
193	  return result;
194	}
195	
196	/**
197	 * Build EngineInstance array and resolutionEngineId from a RigTemplate.
198	 */
199	function buildFromTemplate(
200	  template: RigTemplate,
201	  context: { writ: WritDoc; spiderConfig: SpiderConfig },
202	): { engines: EngineInstance[]; resolutionEngineId?: string } {
203	  const engines: EngineInstance[] = template.engines.map((entry) => ({
204	    id: entry.id,
205	    designId: entry.designId,
206	    status: 'pending' as const,
207	    upstream: entry.upstream ?? [],
208	    givensSpec: resolveGivens(entry.givens, context),
209	  }));
210	  return { engines, resolutionEngineId: template.resolutionEngine };
211	}
212	
213	/**
214	 * Validate all configured rig templates at startup.
215	 * Fails fast on the first error with a '[spider]' prefixed message.
216	 */
217	function validateTemplates(
218	  rigTemplates: Record<string, RigTemplate>,
219	  fabricator: FabricatorApi,
220	): void {
221	  const builtinEngineIds = new Set([
222	    draftEngine.id,
223	    implementEngine.id,
224	    reviewEngine.id,
225	    reviseEngine.id,
226	    sealEngine.id,
227	  ]);
228	
229	  for (const [templateKey, template] of Object.entries(rigTemplates)) {
230	    const engines = template.engines;
231	
232	    // R13: Non-empty check
233	    if (engines.length === 0) {
234	      throw new Error(`[spider] rigTemplates.${templateKey}: template has no engines`);
235	    }
236	
237	    // R6b: Duplicate ID check
238	    const engineIds = new Set<string>();
239	    for (const engine of engines) {
240	      if (engineIds.has(engine.id)) {
241	        throw new Error(
242	          `[spider] rigTemplates.${templateKey}: duplicate engine id "${engine.id}"`
243	        );
244	      }
245	      engineIds.add(engine.id);
246	    }
247	
248	    // R6a: designId check
249	    for (const engine of engines) {
250	      const knownInFabricator = fabricator.getEngineDesign(engine.designId) !== undefined;
251	      const knownBuiltin = builtinEngineIds.has(engine.designId);
252	      if (!knownInFabricator && !knownBuiltin) {
253	        throw new Error(
254	          `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown designId "${engine.designId}"`
255	        );
256	      }
257	    }
258	
259	    // R6c: Upstream reference check
260	    for (const engine of engines) {
261	      for (const upstreamId of engine.upstream ?? []) {
262	        if (!engineIds.has(upstreamId)) {
263	          throw new Error(
264	            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown upstream "${upstreamId}"`
265	          );
266	        }
267	      }
268	    }
269	
270	    // R6d: Cycle detection (DFS)
271	    {
272	      const visiting = new Set<string>();
273	      const visited = new Set<string>();
274	
275	      const visit = (id: string): void => {
276	        if (visited.has(id)) return;
277	        if (visiting.has(id)) {
278	          throw new Error(
279	            `[spider] rigTemplates.${templateKey}: dependency cycle detected involving engine "${id}"`
280	          );
281	        }
282	        visiting.add(id);
283	        const engine = engines.find((e) => e.id === id)!;
284	        for (const dep of engine.upstream ?? []) {
285	          visit(dep);
286	        }
287	        visiting.delete(id);
288	        visited.add(id);
289	      };
290	
291	      for (const engine of engines) {
292	        visit(engine.id);
293	      }
294	    }
295	
296	    // R6e: resolutionEngine check
297	    if (template.resolutionEngine !== undefined && !engineIds.has(template.resolutionEngine)) {
298	      throw new Error(
299	        `[spider] rigTemplates.${templateKey}: resolutionEngine "${template.resolutionEngine}" is not an engine id in this template`
300	      );
301	    }
302	
303	    // R7: Variable reference validation
304	    for (const engine of engines) {
305	      for (const value of Object.values(engine.givens ?? {})) {
306	        if (typeof value === 'string' && value.startsWith('$')) {
307	          const normalized = normalizeVarRef(value);
308	          if (
309	            normalized === '$writ' ||
310	            /^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)
311	          ) {
312	            continue; // valid
313	          }
314	          throw new Error(
315	            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" has unrecognized variable "${value}"`
316	          );
317	        }
318	      }
319	    }
320	  }
321	}
322	
323	// ── Block type type guard ──────────────────────────────────────────────
324	
325	function isBlockType(value: unknown): value is BlockType {
326	  return (
327	    typeof value === 'object' &&
328	    value !== null &&
329	    typeof (value as Record<string, unknown>).id === 'string' &&
330	    typeof (value as Record<string, unknown>).check === 'function'
331	  );
332	}
333	
334	// ── Block type registry ────────────────────────────────────────────────
335	
336	class BlockTypeRegistry {
337	  private readonly types = new Map<string, BlockType>();
338	  private readonly provenance = new Map<string, string>();
339	
340	  register(plugin: LoadedPlugin): void {
341	    if (isLoadedKit(plugin)) {
342	      this.registerFromKit(plugin.kit, plugin.id);
343	    } else if (isLoadedApparatus(plugin)) {
344	      if (plugin.apparatus.supportKit) {
345	        this.registerFromKit(plugin.apparatus.supportKit, plugin.id);
346	      }
347	    }
348	  }
