1	/**
2	 * The Fabricator — guild engine design registry apparatus.
3	 *
4	 * Scans installed engine designs from kit contributions and apparatus supportKits,
5	 * and serves them to the Spider on demand.
6	 *
7	 * The Fabricator does not execute engines. It is a pure query service:
8	 * designs in, designs out.
9	 */
10	
11	import type {
12	  StartupContext,
13	  LoadedPlugin,
14	  LoadedApparatus,
15	  Plugin,
16	} from '@shardworks/nexus-core';
17	import {
18	  guild,
19	  isLoadedKit,
20	  isLoadedApparatus,
21	} from '@shardworks/nexus-core';
22	
23	// ── Public types ──────────────────────────────────────────────────────
24	
25	/** Minimal execution context passed to an engine's run() method. */
26	export interface EngineRunContext {
27	  /** The rig this engine instance belongs to. */
28	  rigId: string;
29	  /** Simple string identity for this engine instance (e.g. 'draft', 'implement'). */
30	  engineId: string;
31	  /** All upstream yields, keyed by engine id. Escape hatch for engines that need to inspect the full upstream chain. */
32	  upstream: Record<string, unknown>;
33	  /**
34	   * Present when this engine was previously blocked and has been restarted.
35	   * Advisory — do not depend on for correctness.
36	   *
37	   * Note: Defined inline to avoid a circular package dependency with spider-apparatus.
38	   * Shape matches spider-apparatus BlockRecord exactly.
39	   */
40	  priorBlock?: {
41	    type: string;
42	    condition: unknown;
43	    blockedAt: string;
44	    message?: string;
45	    lastCheckedAt?: string;
46	  };
47	}
48	
49	/**
50	 * The result of an engine run.
51	 *
52	 * 'completed' — synchronous work done inline, yields are available immediately.
53	 * 'launched'  — async work launched in a session; the Spider polls for completion.
54	 * 'blocked'   — engine is waiting for an external condition; Spider will poll
55	 *               the registered block type's checker and restart when cleared.
56	 */
57	export type EngineRunResult =
58	  | { status: 'completed'; yields: unknown }
59	  | { status: 'launched'; sessionId: string }
60	  | { status: 'blocked'; blockType: string; condition: unknown; message?: string };
61	
62	/**
63	 * An engine design — the unit of work the Fabricator catalogues and the
64	 * Spider executes. Kit authors import this type from @shardworks/fabricator-apparatus.
65	 */
66	export interface EngineDesign {
67	  /** Unique identifier for this engine design (e.g. 'draft', 'implement', 'review'). */
68	  id: string;
69	
70	  /**
71	   * Execute this engine.
72	   *
73	   * @param givens   — the engine's declared inputs, assembled by the Spider.
74	   * @param context  — minimal execution context: engine id and upstream yields.
75	   */
76	  run(givens: Record<string, unknown>, context: EngineRunContext): Promise<EngineRunResult>;
77	
78	  /**
79	   * Assemble yields from a completed session.
80	   *
81	   * Called by the Spider's collect step when a quick engine's session
82	   * reaches a terminal state. The engine looks up whatever it needs
83	   * via guild() — same dependency pattern as run().
84	   *
85	   * @param sessionId — the session to collect yields from (primary input).
86	   * @param givens    — same givens that were passed to run().
87	   * @param context   — same execution context that was passed to run().
88	   *
89	   * If not defined, the Spider uses a generic default:
90	   *   { sessionId, sessionStatus, output? }
91	   *
92	   * Only relevant for quick engines (those that return { status: 'launched' }).
93	   * Clockwork engines return yields directly from run().
94	   */
95	  collect?(sessionId: string, givens: Record<string, unknown>, context: EngineRunContext): Promise<unknown>;
96	}
97	
98	/** Summary info for a registered engine design. */
99	export interface EngineDesignInfo {
100	  /** Engine design id. */
101	  id: string;
102	  /** Plugin id that contributed this design. */
103	  pluginId: string;
104	  /** Whether the design defines a collect() method (indicates quick engine with custom yield assembly). */
105	  hasCollect: boolean;
106	}
107	
108	/** The Fabricator's public API, exposed via `provides`. */
109	export interface FabricatorApi {
110	  /**
111	   * Look up an engine design by ID.
112	   * Returns the design if registered, undefined otherwise.
113	   */
114	  getEngineDesign(id: string): EngineDesign | undefined;
115	
116	  /**
117	   * List all registered engine designs with summary info.
118	   */
119	  listEngineDesigns(): EngineDesignInfo[];
120	}
121	
122	// ── Type guard ────────────────────────────────────────────────────────
123	
124	/** Narrow an unknown value to EngineDesign. */
125	function isEngineDesign(value: unknown): value is EngineDesign {
126	  return (
127	    typeof value === 'object' &&
128	    value !== null &&
129	    typeof (value as Record<string, unknown>).id === 'string' &&
130	    typeof (value as Record<string, unknown>).run === 'function'
131	  );
132	}
133	
134	// ── Implementation ────────────────────────────────────────────────────
135	
136	/** The engine design registry — populated at startup, queried at runtime. */
137	class EngineRegistry {
138	  private readonly designs = new Map<string, EngineDesign>();
139	  private readonly provenance = new Map<string, string>();
140	
141	  /** Register all engine designs from a loaded plugin. */
142	  register(plugin: LoadedPlugin): void {
143	    if (isLoadedKit(plugin)) {
144	      this.registerFromKit(plugin.kit, plugin.id);
145	    } else if (isLoadedApparatus(plugin)) {
146	      if (plugin.apparatus.supportKit) {
147	        this.registerFromKit(plugin.apparatus.supportKit, plugin.id);
148	      }
149	    }
150	  }
151	
152	  /** Extract and register engine designs from a kit (or supportKit) contribution. */
153	  private registerFromKit(kit: Record<string, unknown>, pluginId: string): void {
154	    const rawEngines = kit.engines;
155	    if (typeof rawEngines !== 'object' || rawEngines === null) return;
156	
157	    for (const value of Object.values(rawEngines as Record<string, unknown>)) {
158	      if (isEngineDesign(value)) {
159	        this.designs.set(value.id, value);
160	        this.provenance.set(value.id, pluginId);
161	      }
162	    }
163	  }
164	
165	  /** Look up an engine design by ID. */
166	  get(id: string): EngineDesign | undefined {
167	    return this.designs.get(id);
168	  }
169	
170	  /** List all registered engine designs with summary info. */
171	  list(): EngineDesignInfo[] {
172	    const result: EngineDesignInfo[] = [];
173	    for (const [id, design] of this.designs) {
174	      result.push({
175	        id,
176	        pluginId: this.provenance.get(id) ?? 'unknown',
177	        hasCollect: typeof design.collect === 'function',
178	      });
179	    }
180	    return result;
181	  }
182	}
183	
184	// ── Apparatus factory ─────────────────────────────────────────────────
185	
186	/**
187	 * Create the Fabricator apparatus plugin.
188	 *
189	 * Returns a Plugin with:
190	 * - `consumes: ['engines']` — scans kit/supportKit contributions
191	 * - `provides: FabricatorApi` — the engine design registry API
192	 */
193	export function createFabricator(): Plugin {
194	  const registry = new EngineRegistry();
195	
196	  const api: FabricatorApi = {
197	    getEngineDesign(id: string): EngineDesign | undefined {
198	      return registry.get(id);
199	    },
200	    listEngineDesigns(): EngineDesignInfo[] {
201	      return registry.list();
202	    },
203	  };
204	
205	  return {
206	    apparatus: {
207	      requires: [],
208	      consumes: ['engines'],
209	      provides: api,
210	
211	      start(ctx: StartupContext): void {
212	        const g = guild();
213	
214	        // Scan all already-loaded kits. These fired plugin:initialized before
215	        // any apparatus started, so we can't catch them via events.
216	        for (const kit of g.kits()) {
217	          registry.register(kit);
218	        }
219	
220	        // Subscribe to plugin:initialized for apparatus supportKits that
221	        // fire after us in the startup sequence.
222	        ctx.on('plugin:initialized', (plugin: unknown) => {
223	          const loaded = plugin as LoadedPlugin;
224	          // Skip kits — we already scanned them above.
225	          if (isLoadedApparatus(loaded)) {
226	            registry.register(loaded);
227	          }
228	        });
229	      },
230	    },
231	  };
232	}
