  it('mixed literals and $-variables resolve correctly together', async () => {
    const template: RigTemplate = {
      engines: [{ id: 'only', designId: 'seal', givens: { writ: '$writ', role: 'reviewer', cmd: '$vars.buildCommand' } }],
